__kernel void dynproc_kernel(const int iteration,
                             __global const int* gpuWall,
                             __global int* gpuSrc,
                             __global int* gpuResults,
                             const int cols,
                             const int rows,
                             const int startStep,
                             const int border,
                             const int halo,
                             __local int* prev,
                             __local int* result,
                             __global int* outputBuffer)
{
    (void)rows;
    (void)border;
    (void)halo;
    (void)prev;
    (void)result;
    (void)outputBuffer;

    if (get_global_id(0) != 0)
        return;

    __global int* src = gpuSrc;
    __global int* dst = gpuResults;

    for (int t = 0; t < iteration; ++t) {
        int wallOffset = (startStep + t) * cols;

        for (int n = 0; n < cols; ++n) {
            int m = src[n];
            if (n > 0 && src[n - 1] < m)
                m = src[n - 1];
            if (n < cols - 1 && src[n + 1] < m)
                m = src[n + 1];
            dst[n] = gpuWall[wallOffset + n] + m;
        }

        __global int* temp = src;
        src = dst;
        dst = temp;
    }

    if ((iteration & 1) == 0) {
        for (int n = 0; n < cols; ++n)
            gpuResults[n] = src[n];
    }
}
